const raw = $input.first().json.choices?.[0]?.message?.content || "{}";
let p; try { p = JSON.parse(raw); } catch (e) { p = {}; }
const MAP = {
  bestellung:    { kategorie: "Bestellung, Versand oder Rechnung", team: "Auftrags- & Rechnungsservice" },
  konto:         { kategorie: "Registrierung und Benutzerkonto",   team: "Kundenkonto-Service" },
  digitalzugang: { kategorie: "Zugang zu digitalen Produkten",     team: "Digital-Support" },
  webcode:       { kategorie: "Webcode oder Lizenz",               team: "Lizenzservice" },
  technik:       { kategorie: "Technisches Problem",               team: "Technischer Support" },
  produkt:       { kategorie: "Produkt- oder Programmanfrage",     team: "Produktberatung" },
  datenschutz:   { kategorie: "Datenschutz / rechtliche Frage",    team: "Datenschutz & Recht" },
  sonstiges:     { kategorie: "Sonstiges / manuelle Prüfung",      team: "Service Center (manuelle Sichtung)" }
};
const id = String(p.kategorie_id || "sonstiges").toLowerCase().trim();
const m = MAP[id] || MAP.sonstiges;
const urg = ["Niedrig","Mittel","Hoch"].includes(p.dringlichkeit) ? p.dringlichkeit : "Mittel";
return [{ json: {
  kategorie: m.kategorie,
  team: m.team,
  dringlichkeit: urg,
  begruendung: p.begruendung || "",
  fehlende_infos: Array.isArray(p.fehlende_infos) ? p.fehlende_infos : [],
  antwortentwurf: p.antwortentwurf || "",
  freigabe_hinweis: "Freigabe durch Mitarbeitende erforderlich"
}}];
